<ol>
<li>默认展示所有数据</li>
</ol>
<div class="language-javascript line-numbers-mode" data-ext="js"><pre v-pre class="language-javascript"><code><span class="token keyword">let</span> page <span class="token operator">=</span> <span class="token number">1</span>
<span class="token keyword">let</span> allPage
<span class="token keyword">function</span> <span class="token function">getCommentList</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token function">axios</span><span class="token punctuation">(</span><span class="token punctuation">{</span>
